import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        long count = 0;
        int n = nums.length;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long a = nums[i];
                long b = nums[j];
                long absA = Math.abs(a);
                long absB = Math.abs(b);
                long diff = Math.abs(a - b);
                long sum = Math.abs(a + b);

                long minVal = Math.min(diff, sum);
                long maxVal = Math.max(diff, sum);

                long minAbs = Math.min(absA, absB);
                long maxAbs = Math.max(absA, absB);

                if (minVal <= minAbs && maxVal >= maxAbs) {
                    count++;
                }
            }
        }
        return count;
    }
}
